class Layer:
    def __init__(self, name):
        self.name = name
        self.trainable = True # By default, layers can be trained

model_layers = [
    Layer("Conv1_Edges"),
    Layer("Conv2_Shapes"),
    Layer("Conv3_Objects"),
    Layer("Final_Classification_Layer")
]

def apply_transfer_learning(layers):
    for layer in layers:
        if layer.name != "Final_Classification_Layer":
            layer.trainable = False
            print(f"Froze {layer.name}")
        else:
            print(f"Kept {layer.name} trainable")

apply_transfer_learning(model_layers)

